Here's how to test `DataFetcher` with modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        // Act
        var result = await _sut.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        _handler.StatusCode = HttpStatusCode.InternalServerError;

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no mocking framework needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent),
            });
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async testing** | `async Task` return type — MSTest awaits it automatically |
| **Timeouts** | `[Timeout(5000)]` cancels via `TestContext.CancellationToken` if the test hangs |
| **CancellationToken** | Pass `_testContext.CancellationToken` so timeout actually stops the test |
| **Cancellation verification** | `CreateLinkedTokenSource` links to the test's token, then cancel immediately |
| **Constructor init** | Fields are `readonly`; `TestContext` injected via constructor (MSTest 3.6+) |
| **Sealed class** | Minor perf win, signals the class isn't meant for inheritance |
| **No `[ExpectedException]`** | `Assert.ThrowsExactlyAsync` is scoped and lets you inspect the exception |

The critical detail: **always forward `_testContext.CancellationToken`** to your async calls. Without it, `[Timeout]` has no way to interrupt the operation and the test may hang past the timeout.
